const item = (raw.fileURL || raw.usuario_id) ? raw : (raw.query || raw);

const erros = [];
if (!item.fileURL || String(item.fileURL).trim() === '') erros.push('Parâmetro obrigatório ausente: fileURL');
if (!item.usuario_id || String(item.usuario_id).trim() === '') erros.push('Parâmetro obrigatório ausente: usuario_id');

if (erros.length > 0) {
  return [{ json: { inputs_validos: false, erros, fileURL: item.fileURL || '', usuario_id: item.usuario_id || '' } }];
}
return [{ json: { inputs_validos: true, erros: [], fileURL: item.fileURL, usuario_id: item.usuario_id } }];
} catch (e) {
  return [{ json: { inputs_validos: false, erros: ['CODE_ERROR: ' + (e.message || 'Erro desconhecido')], fileURL: '', usuario_id: '' } }];
}

const item = $input.first().json;
const fileId = item.id;

const prompt = `Você é especialista em extração de dados de faturas de cartão de crédito.

RETORNE SOMENTE JSON válido, sem markdown, sem blocos de código, sem texto adicional.

REGRA CRÍTICA PARA FATURAS MULTI-CARTÃO:
Esta fatura pode conter lançamentos de MÚLTIPLOS cartões (cada um com número diferente).
EXTRAIA os lançamentos de TODOS os cartões em um único array "lancamentos".
NÃO pare na primeira linha "Total R$" — ela é subtotal parcial de um cartão, não o total da fatura.
O total REAL da fatura está na capa (campo "Total a pagar").
Continue extraindo até esgotar TODAS as seções de todos os cartões.

Schema obrigatório:
{
  "emissor": "Nome do banco/emissor (ex: Nubank, Itaú, Sicredi, Bradesco, Mercado Pago)",
  "bandeira": "Visa, Mastercard, Elo, Amex — ou null",
  "titular": "Nome completo do titular ou null",
  "ultimos_digitos": "Últimos 4 dígitos do cartão principal ou null",
  "mes_referencia": "MM/YYYY do mês de referência",
  "data_vencimento": "YYYY-MM-DD ou null",
  "valor_total": 0.00,
  "valor_minimo": 0.00,
  "limite_total": 0.00,
  "limite_disponivel": 0.00,
  "lancamentos": [
    {
      "data_lancamento": "YYYY-MM-DD",
      "descricao": "Descrição completa do lançamento",
      "estabelecimento": "Nome limpo do estabelecimento sem códigos ou datas",
      "valor": 0.00,
      "tipo": "debito",
      "parcela_atual": null,
      "parcela_total": null,
      "cartao_digitos": "4 dígitos do cartão deste lançamento ou null"
    }
  ],
  "total_calculado": 0.00,
  "divergencia": false
}

Regras:
- tipo "credito": estornos, pagamentos recebidos, cashback, devoluções
- tipo "debito": compras, saques, tarifas (padrão)
- valor sempre positivo
- parcelas: se "3/12" → parcela_atual=3, parcela_total=12
- divergencia: true se |total_calculado - valor_total| > 0.50
- cartao_digitos: preencher quando a fatura tiver múltiplos cartões
- Campos não encontrados: null (numéricos: 0)`;

return [{
  json: {
    ...item,
    request_body: {
      model: "gpt-4.1",
      input: [{
        role: "user",
        content: [
          { type: "input_file", file_id: fileId },
          { type: "input_text", text: prompt }
        ]
      }],
      max_output_tokens: 16384
    }
  }
}];

try {
const raw = $input.first().json;
const usuario_id = $('FN - Valida Inputs').first().json.usuario_id;
const fileURL = $('FN - Valida Inputs').first().json.fileURL;

if (raw.status === 'incomplete') {
  const motivo = raw.incomplete_details?.reason ?? 'desconhecido';
  return [{ json: {
    success: false, error_code: 'RESPONSE_TRUNCATED',
    message: 'Resposta cortada (' + motivo + '). Fatura muito longa.',
    response: '⚠️ Fatura muito longa. Aumente max_output_tokens para 32768.',
    usuario_id, fileURL, lancamentos: [], valor_total: 0,
    suggestion: 'Aumente max_output_tokens no FN - Prepara OCR para 32768.'
  }}];
}

let content = '';
try {
  const msgBlock = raw.output.find(o => o.type === 'message');
  const textBlock = msgBlock.content.find(c => c.type === 'output_text');
  content = textBlock.text;
} catch (e) {
  return [{ json: {
    success: false, error_code: 'API_RESPONSE_ERROR',
    message: 'Formato inesperado: ' + JSON.stringify(raw).substring(0, 400),
    response: '⚠️ Erro ao processar resposta da IA. Tente reenviar a fatura.',
    usuario_id, fileURL, lancamentos: [], valor_total: 0,
    suggestion: 'Verifique se o arquivo foi enviado corretamente.'
  }}];
}

content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('JSON não encontrado');
  parsed = JSON.parse(jsonMatch[0]);
} catch (e) {
  return [{ json: {
    success: false, error_code: 'PARSE_ERROR',
    message: 'Erro ao parsear JSON: ' + e.message,
    response: '⚠️ Não consegui ler os dados da fatura. Verifique se é uma fatura de cartão em PDF.',
    usuario_id, fileURL, lancamentos: [], valor_total: 0,
    suggestion: 'Verifique se o arquivo é uma fatura de cartão de crédito válida em PDF.'
  }}];
}

const temDadosValidos = parsed.emissor || (parsed.lancamentos && parsed.lancamentos.length > 0);
if (!temDadosValidos) {
  return [{ json: {
    success: false, error_code: 'EXTRACTION_FAILED',
    message: 'IA não extraiu dados reconhecíveis.',
    response: '⚠️ Não identifiquei dados de fatura no arquivo. Confirme que é uma fatura de cartão em PDF.',
    usuario_id, fileURL, lancamentos: [], valor_total: 0,
    suggestion: 'Reenvie a fatura em PDF legível.'
  }}];
}

const lancamentos = parsed.lancamentos || [];
const valorTotal = parseFloat(parsed.valor_total) || 0;
const totalCalculado = lancamentos.reduce((s, l) => {
  const v = parseFloat(l.valor) || 0;
  return l.tipo === 'credito' ? s - v : s + v;
}, 0);

return [{ json: {
  success: true, usuario_id, fileURL,
  emissor: parsed.emissor || 'Desconhecido',
  bandeira: parsed.bandeira || null,
  titular: parsed.titular || null,
  ultimos_digitos: parsed.ultimos_digitos || '0000',
  mes_referencia: parsed.mes_referencia || '',
  data_vencimento: parsed.data_vencimento || null,
  valor_total: valorTotal,
  valor_minimo: parseFloat(parsed.valor_minimo) || 0,
  limite_total: parseFloat(parsed.limite_total) || 0,
  limite_disponivel: parseFloat(parsed.limite_disponivel) || 0,
  total_calculado: Math.round(totalCalculado * 100) / 100,
  divergencia: parsed.divergencia === true || Math.abs(totalCalculado - valorTotal) > 0.50,
  lancamentos: lancamentos,
  quantidade_lancamentos: lancamentos.length
}}];
} catch (e) {
  return [{ json: { success: false, error_code: 'CODE_ERROR', message: '[FN - Parseia Resposta] ' + (e.message || 'Erro desconhecido'), response: '⚠️ Erro interno ao processar fatura.', lancamentos: [], valor_total: 0 } }];
}

