  resumo = 'Fatura ' + parsed.emissor + ' (' + parsed.mes_referencia + ') processada. ' + inseridos + ' lançamentos registrados (' + jaExistiam + ' já existiam). Total: R$ ' + Number(parsed.valor_total||0).toFixed(2) + '. ID: ' + fatura_id;
