  resumo = 'Fatura ' + parsed.emissor + ' (' + parsed.mes_referencia + ') processada com sucesso. ' + inseridos + ' lançamentos registrados. Total: R$ ' + Number(parsed.valor_total||0).toFixed(2) + '. ID: ' + fatura_id;
} else {
  resumo = 'Fatura ' + parsed.emissor + ' (' + parsed.mes_referencia + ') já estava registrada anteriormente (' + total + ' lançamentos). ID: ' + fatura_id;
